const body = $input.first().json.body || $input.first().json;
const workflow = body.workflow || 'unknown';
const message = body.message || 'War Room action triggered';
const triggeredBy = body.triggeredBy || 'War Room';
const timestamp = body.timestamp || new Date().toISOString();
return [{ json: { workflow, message, triggeredBy, timestamp, success: true } }];
